{
  "task": {
    "task_name": "medical_structured_extraction",
    "task_scope": "仅根据当前任务字段列表完成结构化抽取",
    "field_definitions": [
      {
        "name": "唯一标识符",
        "type": "array",
        "required": false,
        "description": "提取当前文档中出现的所有患者本人身份标识符，仅限患者相关编号，不提取医生工号、机构编号、申请单号等非患者ID。如同时包含住院号、门诊号、病案号、健康卡号、身份证号等，须分别列为独立条目，不得遗漏。保留原始编号中的字母、连字符和前导零；同一类型且编号完全相同的记录不重复输出。",
        "items": {
          "type": "object",
          "properties": {
            "标识符类型": {
              "type": "string",
              "description": "根据原文标签、上下文或编号用途判断该编号对应的类型，必须从枚举值中选择最贴切的一项。若原文明确写明住院号、门诊号、病案号、医保号等，按原标签归类；若无法稳定映射到既有类型，再输出其他。",
              "enum": [
                "住院号",
                "门诊号",
                "急诊号",
                "MRN",
                "医保号",
                "社保号",
                "病案号",
                "健康卡号",
                "身份证号",
                "ID号",
                "其他"
              ]
            },
            "标识符编号": {
              "type": "string",
              "description": "提取与标识符类型对应的原始编号文本，保留字母、数字、连字符、前导零等原始形式，不做改写或补全。仅输出编号本身，不包含住院号、病案号等标签文字。"
            }
          }
        }
      },
      {
        "name": "机构名称",
        "type": "string",
        "required": false,
        "description": "提取出具或签发当前文档的医疗机构全称，优先使用标题、页眉、落款、盖章区或明确的机构字段。只输出机构名称本身，不拼接科室、院区、地址、电话等附加信息；如无明确线索则为 null。"
      },
      {
        "name": "科室信息",
        "type": "string",
        "required": false,
        "description": "提取与当前文档直接对应的就诊、住院或检查所属科室，优先使用科室、就诊科室、申请科室、出院科别等明确字段。只输出单个最相关的科室名称，不拼接病区、床号、医院名称；若无明确科室而仅出现病区，且病区明显代表所属临床单元时，可输出病区名称，否则为 null。"
      },
      {
        "name": "患者姓名",
        "type": "string",
        "required": false,
        "description": "提取患者本人姓名，优先使用姓名、患者姓名、Name 等明确字段，不得误提医生、家属、签字人或联系人姓名。如无明确线索则为 null。"
      },
      {
        "name": "患者性别",
        "type": "string",
        "required": false,
        "description": "提取患者生理性别，只能规范化为男、女、不详。男/Male/男性 统一输出为男，女/Female/女性 统一输出为女；仅当原文明确写明未知、不详、未说明时输出不详；完全无性别线索时为 null。",
        "enum": [
          "男",
          "女",
          "不详"
        ]
      },
      {
        "name": "患者年龄",
        "type": "integer",
        "required": false,
        "description": "提取患者在文档生成时的明确年龄，输出整数岁数，不带单位。仅在原文直接给出年龄时提取，如38岁输出38；不得根据出生日期、身份证号或其他日期自行推算。若仅有月龄、日龄或描述不足以直接确定整岁，则为 null。",
        "minimum": 0
      },
      {
        "name": "出生日期",
        "type": "string",
        "required": false,
        "description": "提取患者明确的出生日期，并统一规范为 YYYY-MM-DD。仅当原文存在出生日期、出生年月日、DOB 等明确字段或等价表达时提取；不得根据年龄、身份证号或其他编号推断。如日期不完整或无明确线索，则为 null。",
        "format": "date"
      },
      {
        "name": "文档类型",
        "type": "string",
        "required": true,
        "description": "文档的主分类，必须从枚举值中选择1个。分类以当前文档的核心内容和正文结构为准，标题仅作辅助参考；具体分类依据以 document_types.json 为准，不得根据附件、局部片段或无关字段偏移主类判断。",
        "enum": [
          "专科检查",
          "其他材料",
          "内镜检查",
          "基因检测",
          "实验室检查",
          "影像检查",
          "治疗记录",
          "生理功能检查",
          "病历记录",
          "病理报告"
        ]
      },
      {
        "name": "文档子类型",
        "type": "string",
        "required": true,
        "description": "文档主类型下的子分类，必须输出且必须从对应主类型的子类型列表中选择；具体规则见 document_types.json。应优先输出能够稳定匹配的最具体子类型。若文档类型为其他材料且无法稳定匹配具体子类，输出未细分；其他主类型也应依据标题、正文结构和关键特征选择最贴近的子类型，不输出 null。"
      },
      {
        "name": "文档摘要",
        "type": "string",
        "required": true,
        "description": "生成一段面向后续Agent做字段组路由判断的高信息密度文档摘要。该摘要不是标题提取，而是用于帮助Agent判断：1）本文档属于哪类内容来源；2）本文档可能支持提取哪些字段组；3）哪些字段组大概率不适合从本文档提取详情。摘要必须基于当前文档正文、标题和关键栏目，优先概括三个维度：内容类型（如病历、检查、病理、治疗、费用、行政流程等）、可提取线索（如患者基本信息、诊断、检查结果、治疗过程、病理结论、时间信息、药物、费用等）、不适用范围（如仅适合分类/路由参考，不适合提取详细诊疗字段）。若文档只覆盖部分字段组，应明确指出其更适合支持哪些字段组；若文档主要是流程单、票据、预约单或其他低信息密度材料，也应明确指出其局限性。输出应为1至3句自然语言摘要，信息具体、便于路由判断，避免空泛评价；禁止照抄大段原文，禁止仅重复标题，禁止输出与字段组判断无关的泛化描述。"
      },
      {
        "name": "文档生效日期",
        "type": "string",
        "required": false,
        "description": "提取最能代表当前文档形成、签发、生效或正式记录完成时间的日期，统一输出为 ISO datetime 格式（YYYY-MM-DDTHH:MM:SS）。仅当原文存在明确日期证据，如报告日期、检查日期、出院日期、记录日期、签发日期等字段时才允许输出；若原文仅有日期无时间，可规范化为当天 00:00:00。若同时出现申请日期、采样日期、检查日期、报告日期等多个日期，优先直接表示文档形成或签发的日期，其次选择与该文档类型最直接对应的日期。禁止使用系统当前日期、文件名时间戳或模糊推断；日期不完整时为 null。",
        "format": "date-time"
      }
    ]
  },
  "output_format": {
    "top_level_contract": {
      "required_keys": [
        "result",
        "audit"
      ],
      "additional_top_level_keys_allowed": false
    },
    "result_policy": {
      "description": "result 仅包含当前任务字段列表定义的字段。",
      "missing_value_style": "null",
      "notes": [
        "required=true 的字段必须输出；无证据时可输出 null，禁止编造。",
        "required=false 的字段建议保持结构稳定；无证据时输出 null。",
        "以下示例仅用于说明结构模式，不代表实际任务必须包含这些字段。最终result字段集合始终以当前任务传入的字段列表为准。"
      ]
    },
    "audit_policy": {
      "description": "audit 默认采用简单扁平结构，以 fields 保存字段级审计项。",
      "default_container": "audit.fields",
      "minimum_item_keys": [
        "raw",
        "value"
      ],
      "recommended_item_keys": [
        "source_id",
        "page_idx",
        "document_id"
      ],
      "notes": [
        "简单场景建议直接使用 audit.fields.<字段名>。",
        "复杂字段组场景可在 audit 顶层增加组级容器，但组内仍建议使用 fields 保存字段级审计项。",
        "audit.raw 必须保留原文片段，audit.value 对应规范化后的结果值。",
        "page_idx 由LLM输出，表示 audit.raw 所在文档页码；无页码信息、非分页文本或无法判断时输出 0。",
        "document_id 更适合由解析与后处理流程注入，默认不要求LLM主动生成。"
      ]
    },
    "canonical_example": {
      "description": "完整双结构模式示例，使用占位符字段名和值，仅用于说明 result 与 audit 的对应关系，不代表固定业务字段集合。",
      "result": {
        "<数组字段A>": [
          {
            "<子字段1>": "<值1>",
            "<子字段2>": "<值2>"
          },
          {
            "<子字段1>": "<值3>",
            "<子字段2>": "<值4>"
          }
        ],
        "<标量字段B>": "<规范化后的字符串值>",
        "<枚举字段C>": "<合法枚举值>",
        "<数字字段D>": 123,
        "<日期字段E>": "<YYYY-MM-DD或YYYY-MM-DDTHH:MM:SS>",
        "<可缺失字段F>": null
      },
      "audit": {
        "fields": {
          "<数组字段A> / [0] / <子字段1>": {
            "raw": "<原文片段1>",
            "value": "<值1>",
            "source_id": "<来源片段ID>",
            "page_idx": 2
          },
          "<数组字段A> / [0] / <子字段2>": {
            "raw": "<原文片段2>",
            "value": "<值2>",
            "source_id": "<来源片段ID>",
            "page_idx": 2
          },
          "<数组字段A> / [1] / <子字段1>": {
            "raw": "<原文片段3>",
            "value": "<值3>",
            "source_id": "<来源片段ID>",
            "page_idx": 3
          },
          "<数组字段A> / [1] / <子字段2>": {
            "raw": "<原文片段4>",
            "value": "<值4>",
            "source_id": "<来源片段ID>",
            "page_idx": 3
          },
          "<标量字段B>": {
            "raw": "<支持该字段的原文片段>",
            "value": "<规范化后的字符串值>",
            "source_id": "<来源片段ID>",
            "page_idx": 1
          },
          "<枚举字段C>": {
            "raw": "<原文枚举表达>",
            "value": "<合法枚举值>",
            "source_id": "<来源片段ID>",
            "page_idx": 1
          },
          "<数字字段D>": {
            "raw": "<原文数字表达>",
            "value": 123,
            "source_id": "<来源片段ID>",
            "page_idx": 1
          },
          "<日期字段E>": {
            "raw": "<原文日期表达>",
            "value": "<YYYY-MM-DD或YYYY-MM-DDTHH:MM:SS>",
            "source_id": "<来源片段ID>",
            "page_idx": 0
          },
          "<可缺失字段F>": {
            "raw": null,
            "value": null,
            "source_id": null,
            "page_idx": 0
          }
        }
      }
    },
    "pattern_examples": {
      "array_field": {
        "description": "数组字段模式示例，突出 result 数组与 audit 路径的对应关系。",
        "result_fragment": {
          "<数组字段>": [
            {
              "<子字段1>": "<值1>",
              "<子字段2>": "<值2>"
            },
            {
              "<子字段1>": "<值3>",
              "<子字段2>": "<值4>"
            }
          ]
        },
        "audit_fragment": {
          "fields": {
            "<数组字段> / [0] / <子字段1>": {
              "raw": "<原文片段1>",
              "value": "<值1>",
              "page_idx": 2
            },
            "<数组字段> / [0] / <子字段2>": {
              "raw": "<原文片段2>",
              "value": "<值2>",
              "page_idx": 2
            },
            "<数组字段> / [1] / <子字段1>": {
              "raw": "<原文片段3>",
              "value": "<值3>",
              "page_idx": 3
            },
            "<数组字段> / [1] / <子字段2>": {
              "raw": "<原文片段4>",
              "value": "<值4>",
              "page_idx": 3
            }
          }
        }
      },
      "missing_value": {
        "description": "字段缺失模式示例，强调 result 与 audit 同时显式输出 null。",
        "result_fragment": {
          "<可缺失字段1>": null,
          "<可缺失字段2>": null
        },
        "audit_fragment": {
          "fields": {
            "<可缺失字段1>": {
              "raw": null,
              "value": null,
              "source_id": null,
              "page_idx": 0
            },
            "<可缺失字段2>": {
              "raw": null,
              "value": null,
              "source_id": null,
              "page_idx": 0
            }
          }
        }
      },
      "group_container": {
        "description": "复杂字段组模式示例。audit 顶层可使用组级容器，但组内仍建议通过 fields 保存字段级审计项。",
        "audit_fragment": {
          "<字段组名>": {
            "fields": {
              "<字段组名> / <字段1>": {
                "raw": "<原文片段或null>",
                "value": "<规范化值或null>",
                "page_idx": 0
              },
              "<字段组名> / [*] / <子字段2>": {
                "raw": "<原文片段或null>",
                "value": "<规范化值或null>",
                "page_idx": 0
              }
            }
          }
        }
      }
    }
  },
  "document_input": {
    "input_mode": "plain_text",
    "text": "<待注入文档文本>"
  },
  "classification_reference": {
    "classification_basis": "分类以文档核心内容和正文结构为准，标题、栏目名、关键词仅作辅助；但当标题或固定模板已明确指向某标准文种，如出院小结、会诊单、转科记录、病假条、麻醉记录时，应优先按该标准文种判定。先在主类型中选择最符合文档主体的类别，再在该主类型下选择最贴近的子类型。若文档核心是检查结果、病理诊断、病历叙述或治疗执行过程，必须优先归入对应主类，不得因出现签字、告知、收费、预约等附属信息而归入其他材料。若同一文档同时出现多类信息，应按主体信息和最终用途判定，而不是按附件或局部片段判定。",
    "doc_types": [
      {
        "name": "病历记录",
        "description": "当文档主体是病史采集、诊疗经过、临床判断、医嘱安排、护理观察或住院总结时归入此类。常见特征包括主诉、现病史、既往史、体格检查、诊断、病程、出院医嘱等病历结构要素；若文档主体是检查结果、病理结论或具体治疗执行过程，则不归此类。",
        "default_subtype": null,
        "subtypes": [
          {
            "name": "门诊病历",
            "guidance": "当文档记录门诊就诊过程，常见标题或栏目包括门诊病历、门诊记录、主诉、现病史、体格检查、初步诊断、处理意见时归入此类。若核心是门诊检查结果单或处方单，不归此类。"
          },
          {
            "name": "入院记录",
            "guidance": "当文档用于记录患者首次入院时的系统评估，常见内容包括主诉、现病史、既往史、个人史、家族史、体格检查、初步诊断时归入此类。若为护士填写的入院评估表，应优先归入入院护理评估记录单。"
          },
          {
            "name": "病程记录",
            "guidance": "当文档按时间连续记录住院期间病情变化、检查结果回报、上级医师查房意见和治疗调整时归入此类。常见信号包括今日病程、查房记录、病情变化、处理意见、连续日期记录等。若标题或固定模板明确为会诊、转科、急诊、抢救记录等专门文种，应优先归对应子类；只有文档主线是连续住院病程时才归此类。"
          },
          {
            "name": "出院小结/记录",
            "guidance": "当文档标题或固定模板明确为出院小结、出院记录、出院总结，且内容用于概括本次住院全过程，常见内容包括入院诊断、诊疗经过、出院诊断、出院情况、出院医嘱时归入此类。若只是病案首页式结构化摘要而缺少叙述性经过，应优先归病案首页；若不是标准出院文书而是整合多类报告的综合叙述，可考虑综合病历。"
          },
          {
            "name": "病案首页",
            "guidance": "当文档以标准化字段汇总患者基本信息、主要诊断、手术操作、ICD编码、住院天数、费用等归档信息时归入此类。该类强调结构化摘要而非长篇病程叙述。"
          },
          {
            "name": "护理记录",
            "guidance": "当文档主体为护士持续记录生命体征、出入量、皮肤情况、卧位、护理措施或观察结果时归入此类。若核心是入院时一次性评估表，应优先归入入院护理评估记录单。"
          },
          {
            "name": "医嘱单",
            "guidance": "当文档主体是医生下达的长期或临时医嘱，常见字段包括药品、剂量、频次、执行时间、检查申请、护理级别、停止/取消医嘱等，且本质是待执行或指令性内容时归入此类。若文档重点是已经实施的治疗过程、给药过程、输血反应、手术步骤或执行结果，则不归此类。"
          },
          {
            "name": "急诊记录",
            "guidance": "当文档记录急诊场景下的接诊经过、急救处理、留观情况或急诊诊断时归入此类。常见标题包含急诊记录、急诊病历、抢救记录。"
          },
          {
            "name": "诊断证明",
            "guidance": "当文档标题或模板明确为诊断证明、疾病证明、诊断证明书，核心是证明患者患病事实、诊断名称、就诊情况或证明用途时归入此类。若核心信息是建议休息天数、病休期限、全休/半休等请假用途，且版式为病休证明或病假条，应优先归病假条。"
          },
          {
            "name": "会诊单/记录",
            "guidance": "当文档用于申请会诊或记录会诊意见，常见字段包括会诊科室、会诊目的、会诊意见、会诊医师签名时归入此类。若只是病程中引用会诊结论而文档主体仍为病程记录，不归此类。"
